mapper.select:
SELECT asset_id
FROM inventory_item
WHERE snapshot_id = #{snapshotId}
  AND category_key LIKE 'weapon!_%' ESCAPE '!'
  AND float_price IS NULL
  AND float_value IS NOT NULL
  AND goods_id IS NOT NULL AND goods_id != ''
  AND price >= #{minPrice}
ORDER BY price DESC, id ASC
LIMIT #{limit}
